import{_ as e,o as d,c as o,ae as l}from"./chunks/framework.BEtfQoF7.js";const f=JSON.parse('{"title":"환경 변수","description":"Claude Code 동작을 제어하는 환경 변수 전체 참조 가이드","frontmatter":{"title":"환경 변수","description":"Claude Code 동작을 제어하는 환경 변수 전체 참조 가이드"},"headers":[],"relativePath":"env-vars.md","filePath":"env-vars.md","lastUpdated":1776205703000}'),c={name:"env-vars.md"};function a(s,t,r,i,n,_){return d(),o("div",null,[...t[0]||(t[0]=[l('<h1 id="환경-변수" tabindex="-1">환경 변수 <a class="header-anchor" href="#환경-변수" aria-label="Permalink to &quot;환경 변수&quot;">​</a></h1><blockquote><p>Claude Code 동작을 제어하는 환경 변수 전체 참조 가이드</p></blockquote><p>Claude Code는 동작을 제어하기 위해 다음 환경 변수를 지원합니다. <code>claude</code>를 실행하기 전 셸에서 설정하거나, <a href="/claude-code-docs-ko/settings.html#available-settings"><code>settings.json</code></a>의 <code>env</code> 키에 구성하여 모든 세션에 적용하거나 팀 전체에 배포할 수 있습니다.</p><table tabindex="0"><thead><tr><th style="text-align:left;">변수</th><th style="text-align:left;">용도</th></tr></thead><tbody><tr><td style="text-align:left;"><code>ANTHROPIC_API_KEY</code></td><td style="text-align:left;"><code>X-Api-Key</code> 헤더로 전송되는 API 키. 설정하면 Claude Pro, Max, Team, Enterprise 구독 대신 이 키가 사용됩니다. 비대화형 모드(<code>-p</code>)에서는 키가 있으면 항상 사용됩니다. 대화형 모드에서는 구독을 재정의하기 전 한 번 승인을 요청합니다. 구독을 대신 사용하려면 <code>unset ANTHROPIC_API_KEY</code>를 실행하세요.</td></tr><tr><td style="text-align:left;"><code>ANTHROPIC_AUTH_TOKEN</code></td><td style="text-align:left;"><code>Authorization</code> 헤더의 커스텀 값 (<code>Bearer </code> 접두사가 자동으로 추가됨)</td></tr><tr><td style="text-align:left;"><code>ANTHROPIC_BASE_URL</code></td><td style="text-align:left;">API 엔드포인트를 재정정하여 프록시나 게이트웨이를 통해 요청을 라우팅합니다. 1파티가 아닌 호스트로 설정하면 <a href="/claude-code-docs-ko/mcp.html#scale-with-mcp-tool-search">MCP tool search</a>가 기본적으로 비활성화됩니다. 프록시가 <code>tool_reference</code> 블록을 전달하는 경우 <code>ENABLE_TOOL_SEARCH=true</code>를 설정하세요.</td></tr><tr><td style="text-align:left;"><code>ANTHROPIC_BEDROCK_BASE_URL</code></td><td style="text-align:left;">Bedrock 엔드포인트 URL 재정정. 커스텀 Bedrock 엔드포인트나 <a href="/claude-code-docs-ko/llm-gateway.html">LLM gateway</a>를 통해 라우팅할 때 사용. <a href="/claude-code-docs-ko/amazon-bedrock.html">Amazon Bedrock</a> 참조</td></tr><tr><td style="text-align:left;"><code>ANTHROPIC_BEDROCK_MANTLE_BASE_URL</code></td><td style="text-align:left;">Bedrock Mantle 엔드포인트 URL 재정정. <a href="/claude-code-docs-ko/amazon-bedrock.html#use-the-mantle-endpoint">Mantle endpoint</a> 참조</td></tr><tr><td style="text-align:left;"><code>ANTHROPIC_BETAS</code></td><td style="text-align:left;">API 요청에 포함할 추가 <code>anthropic-beta</code> 헤더 값 (쉼표로 구분). Claude Code는 필요한 베타 헤더를 이미 전송하며, Claude Code가 네이티브 지원을 추가하기 전에 <a href="https://platform.claude.com/docs/en/api/beta-headers" target="_blank" rel="noreferrer">Anthropic API beta</a>에 옵트인하는 데 사용합니다. <a href="/claude-code-docs-ko/cli-reference.html#cli-flags"><code>--betas</code> 플래그</a>와 달리 API 키 인증이 필요 없으며 Claude.ai 구독을 포함한 모든 인증 방법에서 동작합니다.</td></tr><tr><td style="text-align:left;"><code>ANTHROPIC_CUSTOM_HEADERS</code></td><td style="text-align:left;">요청에 추가할 커스텀 헤더 (<code>Name: Value</code> 형식, 여러 헤더는 줄바꿈으로 구분)</td></tr><tr><td style="text-align:left;"><code>ANTHROPIC_CUSTOM_MODEL_OPTION</code></td><td style="text-align:left;"><code>/model</code> 선택기에 커스텀 항목으로 추가할 모델 ID. 기본 제공 별칭을 대체하지 않고 비표준 또는 게이트웨이별 모델을 선택 가능하게 합니다. <a href="/claude-code-docs-ko/model-config.html#add-a-custom-model-option">Model configuration</a> 참조</td></tr><tr><td style="text-align:left;"><code>ANTHROPIC_CUSTOM_MODEL_OPTION_DESCRIPTION</code></td><td style="text-align:left;"><code>/model</code> 선택기에서 커스텀 모델 항목의 설명. 미설정 시 <code>Custom model (&lt;model-id&gt;)</code>가 기본값</td></tr><tr><td style="text-align:left;"><code>ANTHROPIC_CUSTOM_MODEL_OPTION_NAME</code></td><td style="text-align:left;"><code>/model</code> 선택기에서 커스텀 모델 항목의 표시 이름. 미설정 시 모델 ID가 기본값</td></tr><tr><td style="text-align:left;"><code>ANTHROPIC_CUSTOM_MODEL_OPTION_SUPPORTED_CAPABILITIES</code></td><td style="text-align:left;"><a href="/claude-code-docs-ko/model-config.html#customize-pinned-model-display-and-capabilities">Model configuration</a> 참조</td></tr><tr><td style="text-align:left;"><code>ANTHROPIC_DEFAULT_HAIKU_MODEL</code></td><td style="text-align:left;"><a href="/claude-code-docs-ko/model-config.html#environment-variables">Model configuration</a> 참조</td></tr><tr><td style="text-align:left;"><code>ANTHROPIC_DEFAULT_HAIKU_MODEL_DESCRIPTION</code></td><td style="text-align:left;"><a href="/claude-code-docs-ko/model-config.html#customize-pinned-model-display-and-capabilities">Model configuration</a> 참조</td></tr><tr><td style="text-align:left;"><code>ANTHROPIC_DEFAULT_HAIKU_MODEL_NAME</code></td><td style="text-align:left;"><a href="/claude-code-docs-ko/model-config.html#customize-pinned-model-display-and-capabilities">Model configuration</a> 참조</td></tr><tr><td style="text-align:left;"><code>ANTHROPIC_DEFAULT_HAIKU_MODEL_SUPPORTED_CAPABILITIES</code></td><td style="text-align:left;"><a href="/claude-code-docs-ko/model-config.html#customize-pinned-model-display-and-capabilities">Model configuration</a> 참조</td></tr><tr><td style="text-align:left;"><code>ANTHROPIC_DEFAULT_OPUS_MODEL</code></td><td style="text-align:left;"><a href="/claude-code-docs-ko/model-config.html#environment-variables">Model configuration</a> 참조</td></tr><tr><td style="text-align:left;"><code>ANTHROPIC_DEFAULT_OPUS_MODEL_DESCRIPTION</code></td><td style="text-align:left;"><a href="/claude-code-docs-ko/model-config.html#customize-pinned-model-display-and-capabilities">Model configuration</a> 참조</td></tr><tr><td style="text-align:left;"><code>ANTHROPIC_DEFAULT_OPUS_MODEL_NAME</code></td><td style="text-align:left;"><a href="/claude-code-docs-ko/model-config.html#customize-pinned-model-display-and-capabilities">Model configuration</a> 참조</td></tr><tr><td style="text-align:left;"><code>ANTHROPIC_DEFAULT_OPUS_MODEL_SUPPORTED_CAPABILITIES</code></td><td style="text-align:left;"><a href="/claude-code-docs-ko/model-config.html#customize-pinned-model-display-and-capabilities">Model configuration</a> 참조</td></tr><tr><td style="text-align:left;"><code>ANTHROPIC_DEFAULT_SONNET_MODEL</code></td><td style="text-align:left;"><a href="/claude-code-docs-ko/model-config.html#environment-variables">Model configuration</a> 참조</td></tr><tr><td style="text-align:left;"><code>ANTHROPIC_DEFAULT_SONNET_MODEL_DESCRIPTION</code></td><td style="text-align:left;"><a href="/claude-code-docs-ko/model-config.html#customize-pinned-model-display-and-capabilities">Model configuration</a> 참조</td></tr><tr><td style="text-align:left;"><code>ANTHROPIC_DEFAULT_SONNET_MODEL_NAME</code></td><td style="text-align:left;"><a href="/claude-code-docs-ko/model-config.html#customize-pinned-model-display-and-capabilities">Model configuration</a> 참조</td></tr><tr><td style="text-align:left;"><code>ANTHROPIC_DEFAULT_SONNET_MODEL_SUPPORTED_CAPABILITIES</code></td><td style="text-align:left;"><a href="/claude-code-docs-ko/model-config.html#customize-pinned-model-display-and-capabilities">Model configuration</a> 참조</td></tr><tr><td style="text-align:left;"><code>ANTHROPIC_FOUNDRY_API_KEY</code></td><td style="text-align:left;">Microsoft Foundry 인증용 API 키 (<a href="/claude-code-docs-ko/microsoft-foundry.html">Microsoft Foundry</a> 참조)</td></tr><tr><td style="text-align:left;"><code>ANTHROPIC_FOUNDRY_BASE_URL</code></td><td style="text-align:left;">Foundry 리소스의 전체 기본 URL (예: <code>https://my-resource.services.ai.azure.com/anthropic</code>). <code>ANTHROPIC_FOUNDRY_RESOURCE</code>의 대안 (<a href="/claude-code-docs-ko/microsoft-foundry.html">Microsoft Foundry</a> 참조)</td></tr><tr><td style="text-align:left;"><code>ANTHROPIC_FOUNDRY_RESOURCE</code></td><td style="text-align:left;">Foundry 리소스 이름 (예: <code>my-resource</code>). <code>ANTHROPIC_FOUNDRY_BASE_URL</code>이 설정되지 않은 경우 필수 (<a href="/claude-code-docs-ko/microsoft-foundry.html">Microsoft Foundry</a> 참조)</td></tr><tr><td style="text-align:left;"><code>ANTHROPIC_MODEL</code></td><td style="text-align:left;">사용할 모델 설정 이름 (<a href="/claude-code-docs-ko/model-config.html#environment-variables">Model Configuration</a> 참조)</td></tr><tr><td style="text-align:left;"><code>ANTHROPIC_SMALL_FAST_MODEL</code></td><td style="text-align:left;">[사용 중단됨] 백그라운드 작업용 Haiku 클래스 모델 이름 (<a href="/claude-code-docs-ko/costs.html">Costs</a> 참조)</td></tr><tr><td style="text-align:left;"><code>ANTHROPIC_SMALL_FAST_MODEL_AWS_REGION</code></td><td style="text-align:left;">Bedrock 또는 Bedrock Mantle 사용 시 Haiku 클래스 모델의 AWS 리전 재정정</td></tr><tr><td style="text-align:left;"><code>ANTHROPIC_VERTEX_BASE_URL</code></td><td style="text-align:left;">Vertex AI 엔드포인트 URL 재정정. 커스텀 Vertex 엔드포인트나 <a href="/claude-code-docs-ko/llm-gateway.html">LLM gateway</a> 라우팅에 사용. <a href="/claude-code-docs-ko/google-vertex-ai.html">Google Vertex AI</a> 참조</td></tr><tr><td style="text-align:left;"><code>ANTHROPIC_VERTEX_PROJECT_ID</code></td><td style="text-align:left;">Vertex AI용 GCP 프로젝트 ID. <a href="/claude-code-docs-ko/google-vertex-ai.html">Google Vertex AI</a> 사용 시 필수</td></tr><tr><td style="text-align:left;"><code>API_TIMEOUT_MS</code></td><td style="text-align:left;">API 요청 타임아웃 (밀리초, 기본값: 600000/10분, 최대: 2147483647). 느린 네트워크나 프록시 사용 시 요청이 타임아웃되면 이 값을 늘리세요. 최대값을 초과하면 내부 타이머가 오버플로우되어 요청이 즉시 실패합니다.</td></tr><tr><td style="text-align:left;"><code>AWS_BEARER_TOKEN_BEDROCK</code></td><td style="text-align:left;">Bedrock 인증용 API 키 (<a href="https://aws.amazon.com/blogs/machine-learning/accelerate-ai-development-with-amazon-bedrock-api-keys/" target="_blank" rel="noreferrer">Bedrock API keys</a> 참조)</td></tr><tr><td style="text-align:left;"><code>BASH_DEFAULT_TIMEOUT_MS</code></td><td style="text-align:left;">장시간 실행 bash 명령의 기본 타임아웃 (기본값: 120000/2분)</td></tr><tr><td style="text-align:left;"><code>BASH_MAX_OUTPUT_LENGTH</code></td><td style="text-align:left;">bash 출력이 중간에서 잘리기 전의 최대 문자 수</td></tr><tr><td style="text-align:left;"><code>BASH_MAX_TIMEOUT_MS</code></td><td style="text-align:left;">모델이 장시간 실행 bash 명령에 설정할 수 있는 최대 타임아웃 (기본값: 600000/10분)</td></tr><tr><td style="text-align:left;"><code>CCR_FORCE_BUNDLE</code></td><td style="text-align:left;"><code>1</code>로 설정하면 GitHub 접근이 가능할 때도 <a href="/claude-code-docs-ko/claude-code-on-the-web.html#send-local-repositories-without-github"><code>claude --remote</code></a>가 로컬 리포지토리를 번들하여 업로드하도록 강제합니다.</td></tr><tr><td style="text-align:left;"><code>CLAUDECODE</code></td><td style="text-align:left;">Claude Code가 생성하는 셸 환경에서 <code>1</code>로 설정됨 (Bash 도구, tmux 세션). <a href="/claude-code-docs-ko/hooks.html">hooks</a>나 <a href="/claude-code-docs-ko/statusline.html">status line</a> 명령에서는 설정되지 않습니다. Claude Code가 생성한 셸에서 실행 중인지 감지하는 데 사용합니다.</td></tr><tr><td style="text-align:left;"><code>CLAUDE_AGENT_SDK_DISABLE_BUILTIN_AGENTS</code></td><td style="text-align:left;"><code>1</code>로 설정하면 Explore, Plan 같은 모든 내장 <a href="/claude-code-docs-ko/sub-agents.html">subagent</a> 유형을 비활성화합니다. 비대화형 모드(<code>-p</code> 플래그)에만 적용됩니다. 빈 상태의 SDK 사용자에게 유용합니다.</td></tr><tr><td style="text-align:left;"><code>CLAUDE_AGENT_SDK_MCP_NO_PREFIX</code></td><td style="text-align:left;"><code>1</code>로 설정하면 SDK 생성 MCP 서버의 도구 이름에서 <code>mcp__&lt;server&gt;__</code> 접두사를 생략합니다. 도구가 원래 이름을 사용합니다. SDK 전용.</td></tr><tr><td style="text-align:left;"><code>CLAUDE_AUTOCOMPACT_PCT_OVERRIDE</code></td><td style="text-align:left;">자동 압축이 트리거되는 컨텍스트 용량의 비율(1-100)을 설정합니다. 기본적으로 약 95%에서 트리거됩니다. <code>50</code> 같은 낮은 값으로 더 일찍 압축하도록 설정할 수 있습니다. 기본 임계값보다 높은 값은 효과가 없습니다. 메인 대화와 서브에이전트 모두에 적용됩니다. 이 비율은 <a href="/claude-code-docs-ko/statusline.html">status line</a>에서 사용 가능한 <code>context_window.used_percentage</code> 필드와 정렬됩니다.</td></tr><tr><td style="text-align:left;"><code>CLAUDE_AUTO_BACKGROUND_TASKS</code></td><td style="text-align:left;"><code>1</code>로 설정하면 장시간 실행되는 에이전트 작업의 자동 백그라운드화를 강제 활성화합니다. 활성화 시 서브에이전트는 약 2분 실행 후 백그라운드로 이동합니다.</td></tr><tr><td style="text-align:left;"><code>CLAUDE_BASH_MAINTAIN_PROJECT_WORKING_DIR</code></td><td style="text-align:left;">메인 세션에서 각 Bash 또는 PowerShell 명령 실행 후 원래 작업 디렉토리로 돌아갑니다.</td></tr><tr><td style="text-align:left;"><code>CLAUDE_CODE_ACCESSIBILITY</code></td><td style="text-align:left;"><code>1</code>로 설정하면 네이티브 터미널 커서를 표시하고 반전 텍스트 커서 표시기를 비활성화합니다. macOS Zoom 같은 화면 돋보기가 커서 위치를 추적할 수 있게 합니다.</td></tr><tr><td style="text-align:left;"><code>CLAUDE_CODE_ADDITIONAL_DIRECTORIES_CLAUDE_MD</code></td><td style="text-align:left;"><code>1</code>로 설정하면 <code>--add-dir</code>로 지정된 디렉토리에서 메모리 파일을 로드합니다. <code>CLAUDE.md</code>, <code>.claude/CLAUDE.md</code>, <code>.claude/rules/*.md</code>, <code>CLAUDE.local.md</code>를 로드합니다. 기본적으로 추가 디렉토리는 메모리 파일을 로드하지 않습니다.</td></tr><tr><td style="text-align:left;"><code>CLAUDE_CODE_API_KEY_HELPER_TTL_MS</code></td><td style="text-align:left;"><a href="/claude-code-docs-ko/settings.html#available-settings"><code>apiKeyHelper</code></a> 사용 시 자격 증명을 새로 고칠 간격 (밀리초)</td></tr><tr><td style="text-align:left;"><code>CLAUDE_CODE_AUTO_COMPACT_WINDOW</code></td><td style="text-align:left;">자동 압축 계산에 사용할 컨텍스트 용량 (토큰). 기본값은 모델의 컨텍스트 윈도우: 표준 모델 200K, <a href="/claude-code-docs-ko/model-config.html#extended-context">확장 컨텍스트</a> 모델 1M. 1M 모델에서 <code>500000</code> 같은 낮은 값을 사용하면 압축 목적으로 윈도우를 500K로 처리합니다. 모델의 실제 컨텍스트 윈도우로 상한됩니다. <code>CLAUDE_AUTOCOMPACT_PCT_OVERRIDE</code>는 이 값의 백분율로 적용됩니다.</td></tr><tr><td style="text-align:left;"><code>CLAUDE_CODE_AUTO_CONNECT_IDE</code></td><td style="text-align:left;">자동 <a href="/claude-code-docs-ko/vs-code.html">IDE 연결</a>을 재정정합니다. 기본적으로 지원되는 IDE의 통합 터미널에서 실행 시 Claude Code가 자동 연결합니다. <code>false</code>로 설정하면 연결을 방지하고, <code>true</code>로 설정하면 tmux가 부모 터미널을 가리는 경우처럼 자동 감지가 실패할 때 연결을 시도합니다.</td></tr><tr><td style="text-align:left;"><code>CLAUDE_CODE_CERT_STORE</code></td><td style="text-align:left;">TLS 연결용 CA 인증서 소스 목록 (쉼표로 구분). <code>bundled</code>은 Claude Code에 번들된 Mozilla CA 세트, <code>system</code>은 OS 신뢰 저장소. 기본값은 <code>bundled,system</code>. 시스템 저장소 통합에는 네이티브 바이너리 배포가 필요합니다.</td></tr><tr><td style="text-align:left;"><code>CLAUDE_CODE_CLIENT_CERT</code></td><td style="text-align:left;">mTLS 인증용 클라이언트 인증서 파일 경로</td></tr><tr><td style="text-align:left;"><code>CLAUDE_CODE_CLIENT_KEY</code></td><td style="text-align:left;">mTLS 인증용 클라이언트 개인 키 파일 경로</td></tr><tr><td style="text-align:left;"><code>CLAUDE_CODE_CLIENT_KEY_PASSPHRASE</code></td><td style="text-align:left;">암호화된 CLAUDE_CODE_CLIENT_KEY의 암호 (선택사항)</td></tr><tr><td style="text-align:left;"><code>CLAUDE_CODE_DEBUG_LOGS_DIR</code></td><td style="text-align:left;">디버그 로그 파일 경로 재정정. 이름과 달리 디렉토리가 아닌 파일 경로입니다. <code>--debug</code>나 <code>/debug</code>로 디버그 모드를 별도로 활성화해야 합니다. 기본값: <code>~/.claude/debug/&lt;session-id&gt;.txt</code></td></tr><tr><td style="text-align:left;"><code>CLAUDE_CODE_DEBUG_LOG_LEVEL</code></td><td style="text-align:left;">디버그 로그 파일에 기록할 최소 로그 레벨. 값: <code>verbose</code>, <code>debug</code>(기본), <code>info</code>, <code>warn</code>, <code>error</code>. 전체 status line 명령 출력 같은 대량 진단을 포함하려면 <code>verbose</code>로 설정하고, 노이즈를 줄이려면 <code>error</code>로 올리세요.</td></tr><tr><td style="text-align:left;"><code>CLAUDE_CODE_DISABLE_1M_CONTEXT</code></td><td style="text-align:left;"><code>1</code>로 설정하면 <a href="/claude-code-docs-ko/model-config.html#extended-context">1M 컨텍스트 윈도우</a> 지원을 비활성화합니다. 설정 시 1M 모델 변형이 모델 선택기에서 사용 불가능합니다. 규정 준수 요구사항이 있는 엔터프라이즈 환경에 유용합니다.</td></tr><tr><td style="text-align:left;"><code>CLAUDE_CODE_DISABLE_ADAPTIVE_THINKING</code></td><td style="text-align:left;"><code>1</code>로 설정하면 Opus 4.6 및 Sonnet 4.6의 <a href="/claude-code-docs-ko/model-config.html#adjust-effort-level">적응 추론</a>을 비활성화합니다. 비활성화 시 <code>MAX_THINKING_TOKENS</code>로 제어되는 고정 추론 예산으로 대체됩니다.</td></tr><tr><td style="text-align:left;"><code>CLAUDE_CODE_DISABLE_ATTACHMENTS</code></td><td style="text-align:left;"><code>1</code>로 설정하면 첨부 파일 처리를 비활성화합니다. <code>@</code> 구문의 파일 언급이 확장된 파일 콘텐츠 대신 일반 텍스트로 전송됩니다.</td></tr><tr><td style="text-align:left;"><code>CLAUDE_CODE_DISABLE_AUTO_MEMORY</code></td><td style="text-align:left;"><code>1</code>로 설정하면 <a href="/claude-code-docs-ko/memory.html#auto-memory">자동 메모리</a>를 비활성화합니다. <code>0</code>으로 설정하면 점진적 롤아웃 중에 강제 활성화합니다. 비활성화 시 Claude는 자동 메모리 파일을 생성하거나 로드하지 않습니다.</td></tr><tr><td style="text-align:left;"><code>CLAUDE_CODE_DISABLE_BACKGROUND_TASKS</code></td><td style="text-align:left;"><code>1</code>로 설정하면 Bash 및 서브에이전트 도구의 <code>run_in_background</code> 매개변수, 자동 백그라운드화, Ctrl+B 단축키를 포함한 모든 백그라운드 작업 기능을 비활성화합니다.</td></tr><tr><td style="text-align:left;"><code>CLAUDE_CODE_DISABLE_CLAUDE_MDS</code></td><td style="text-align:left;"><code>1</code>로 설정하면 사용자, 프로젝트, 자동 메모리 파일을 포함한 모든 CLAUDE.md 메모리 파일을 컨텍스트에 로드하지 않습니다.</td></tr><tr><td style="text-align:left;"><code>CLAUDE_CODE_DISABLE_CRON</code></td><td style="text-align:left;"><code>1</code>로 설정하면 <a href="/claude-code-docs-ko/scheduled-tasks.html">예약 작업</a>을 비활성화합니다. <code>/loop</code> 스킬과 크론 도구를 사용할 수 없으며 이미 예약된 작업이 중지됩니다.</td></tr><tr><td style="text-align:left;"><code>CLAUDE_CODE_DISABLE_EXPERIMENTAL_BETAS</code></td><td style="text-align:left;"><code>1</code>로 설정하면 API 요청에서 Anthropic 전용 <code>anthropic-beta</code> 요청 헤더와 베타 도구 스키마 필드(<code>defer_loading</code>, <code>eager_input_streaming</code> 등)를 제거합니다. 프록시 게이트웨이가 &quot;Unexpected value(s) for the <code>anthropic-beta</code> header&quot; 같은 에러로 요청을 거부할 때 사용합니다.</td></tr><tr><td style="text-align:left;"><code>CLAUDE_CODE_DISABLE_FAST_MODE</code></td><td style="text-align:left;"><code>1</code>로 설정하면 <a href="/claude-code-docs-ko/fast-mode.html">fast mode</a>를 비활성화합니다.</td></tr><tr><td style="text-align:left;"><code>CLAUDE_CODE_DISABLE_FEEDBACK_SURVEY</code></td><td style="text-align:left;"><code>1</code>로 설정하면 &quot;How is Claude doing?&quot; 세션 품질 설문을 비활성화합니다. <code>DISABLE_TELEMETRY</code>나 <code>CLAUDE_CODE_DISABLE_NONESSENTIAL_TRAFFIC</code>이 설정되어도 설문이 비활성화됩니다. <a href="/claude-code-docs-ko/data-usage.html#session-quality-surveys">Session quality surveys</a> 참조.</td></tr><tr><td style="text-align:left;"><code>CLAUDE_CODE_DISABLE_FILE_CHECKPOINTING</code></td><td style="text-align:left;"><code>1</code>로 설정하면 파일 <a href="/claude-code-docs-ko/checkpointing.html">체크포인팅</a>을 비활성화합니다. <code>/rewind</code> 명령으로 코드 변경을 복원할 수 없습니다.</td></tr><tr><td style="text-align:left;"><code>CLAUDE_CODE_DISABLE_GIT_INSTRUCTIONS</code></td><td style="text-align:left;"><code>1</code>로 설정하면 Claude의 시스템 프롬프트에서 내장 커밋/PR 워크플로우 지침과 git 상태 스냅샷을 제거합니다. 자체 git 워크플로우 스킬을 사용할 때 유용합니다. <a href="/claude-code-docs-ko/settings.html#available-settings"><code>includeGitInstructions</code></a> 설정보다 우선합니다.</td></tr><tr><td style="text-align:left;"><code>CLAUDE_CODE_DISABLE_LEGACY_MODEL_REMAP</code></td><td style="text-align:left;"><code>1</code>로 설정하면 Anthropic API에서 Opus 4.0 및 4.1을 현재 Opus 버전으로 자동 재매핑하지 않습니다. 이전 모델을 고정하려는 경우 사용하세요. Bedrock, Vertex, Foundry에서는 재매핑이 실행되지 않습니다.</td></tr><tr><td style="text-align:left;"><code>CLAUDE_CODE_DISABLE_MOUSE</code></td><td style="text-align:left;"><code>1</code>로 설정하면 <a href="/claude-code-docs-ko/fullscreen.html">전체화면 렌더링</a>에서 마우스 추적을 비활성화합니다. <code>PgUp</code>/<code>PgDn</code> 키보드 스크롤은 계속 동작합니다. 터미널의 기본 복사 선택 동작을 유지하려면 이 옵션을 사용하세요.</td></tr><tr><td style="text-align:left;"><code>CLAUDE_CODE_DISABLE_NONESSENTIAL_TRAFFIC</code></td><td style="text-align:left;"><code>DISABLE_AUTOUPDATER</code>, <code>DISABLE_FEEDBACK_COMMAND</code>, <code>DISABLE_ERROR_REPORTING</code>, <code>DISABLE_TELEMETRY</code>를 모두 설정하는 것과 동일합니다.</td></tr><tr><td style="text-align:left;"><code>CLAUDE_CODE_DISABLE_NONSTREAMING_FALLBACK</code></td><td style="text-align:left;"><code>1</code>로 설정하면 스트리밍 요청이 중간에 실패할 때 비스트리밍 폴백을 비활성화합니다. 스트리밍 에러가 재시도 레이어로 전파됩니다. 프록시/게이트웨이가 폴백으로 인해 도구 실행이 중복되는 경우 유용합니다.</td></tr><tr><td style="text-align:left;"><code>CLAUDE_CODE_DISABLE_OFFICIAL_MARKETPLACE_AUTOINSTALL</code></td><td style="text-align:left;"><code>1</code>로 설정하면 첫 실행 시 공식 플러그인 마켓플레이스 자동 추가를 건너뜁니다.</td></tr><tr><td style="text-align:left;"><code>CLAUDE_CODE_DISABLE_TERMINAL_TITLE</code></td><td style="text-align:left;"><code>1</code>로 설정하면 대화 컨텍스트 기반의 자동 터미널 제목 업데이트를 비활성화합니다.</td></tr><tr><td style="text-align:left;"><code>CLAUDE_CODE_DISABLE_THINKING</code></td><td style="text-align:left;"><code>1</code>로 설정하면 모델 지원이나 다른 설정과 관계없이 <a href="https://platform.claude.com/docs/en/build-with-claude/extended-thinking" target="_blank" rel="noreferrer">확장 사고</a>를 강제 비활성화합니다. <code>MAX_THINKING_TOKENS=0</code>보다 더 직접적입니다.</td></tr><tr><td style="text-align:left;"><code>CLAUDE_CODE_EFFORT_LEVEL</code></td><td style="text-align:left;">지원되는 모델의 노력 수준을 설정합니다. 값: <code>low</code>, <code>medium</code>, <code>high</code>, <code>max</code>(Opus 4.6 전용), 또는 <code>auto</code>(모델 기본값). <code>/effort</code> 및 <code>effortLevel</code> 설정보다 우선합니다. <a href="/claude-code-docs-ko/model-config.html#adjust-effort-level">노력 수준 조정</a> 참조.</td></tr><tr><td style="text-align:left;"><code>CLAUDE_CODE_ENABLE_FINE_GRAINED_TOOL_STREAMING</code></td><td style="text-align:left;"><code>1</code>로 설정하면 세분화된 도구 입력 스트리밍을 강제 활성화합니다. 미설정 시 API가 도구 입력 매개변수를 완전히 버퍼링한 후 델타 이벤트를 전송하여 대형 도구 입력에서 표시가 지연될 수 있습니다. Anthropic API 전용: Bedrock, Vertex, Foundry에는 효과가 없습니다.</td></tr><tr><td style="text-align:left;"><code>CLAUDE_CODE_ENABLE_PROMPT_SUGGESTION</code></td><td style="text-align:left;"><code>false</code>로 설정하면 프롬프트 제안을 비활성화합니다 (<code>/config</code>의 &quot;Prompt suggestions&quot; 토글). Claude가 응답한 후 프롬프트 입력에 나타나는 회색 예측 텍스트입니다. <a href="/claude-code-docs-ko/interactive-mode.html#prompt-suggestions">Prompt suggestions</a> 참조.</td></tr><tr><td style="text-align:left;"><code>CLAUDE_CODE_ENABLE_TASKS</code></td><td style="text-align:left;"><code>1</code>로 설정하면 비대화형 모드(<code>-p</code> 플래그)에서 작업 추적 시스템을 활성화합니다. 대화형 모드에서는 기본적으로 활성화됩니다. <a href="/claude-code-docs-ko/interactive-mode.html#task-list">작업 목록</a> 참조.</td></tr><tr><td style="text-align:left;"><code>CLAUDE_CODE_ENABLE_TELEMETRY</code></td><td style="text-align:left;"><code>1</code>로 설정하면 메트릭 및 로깅용 OpenTelemetry 데이터 수집을 활성화합니다. OTel 익스포터 구성 전에 필수입니다. <a href="/claude-code-docs-ko/monitoring-usage.html">Monitoring</a> 참조.</td></tr><tr><td style="text-align:left;"><code>CLAUDE_CODE_EXIT_AFTER_STOP_DELAY</code></td><td style="text-align:left;">쿼리 루프가 유휴 상태가 된 후 자동 종료까지 대기할 시간 (밀리초). SDK 모드를 사용하는 자동화 워크플로우 및 스크립트에 유용합니다.</td></tr><tr><td style="text-align:left;"><code>CLAUDE_CODE_EXPERIMENTAL_AGENT_TEAMS</code></td><td style="text-align:left;"><code>1</code>로 설정하면 <a href="/claude-code-docs-ko/agent-teams.html">agent teams</a>를 활성화합니다. 에이전트 팀은 실험적 기능으로 기본적으로 비활성화됩니다.</td></tr><tr><td style="text-align:left;"><code>CLAUDE_CODE_FILE_READ_MAX_OUTPUT_TOKENS</code></td><td style="text-align:left;">파일 읽기의 기본 토큰 제한을 재정정합니다. 더 큰 파일을 전체로 읽어야 할 때 유용합니다.</td></tr><tr><td style="text-align:left;"><code>CLAUDE_CODE_GIT_BASH_PATH</code></td><td style="text-align:left;">Windows 전용: Git Bash 실행 파일 경로(<code>bash.exe</code>). Git Bash가 설치되었지만 PATH에 없을 때 사용. <a href="/claude-code-docs-ko/setup.html#set-up-on-windows">Windows 설정</a> 참조</td></tr><tr><td style="text-align:left;"><code>CLAUDE_CODE_GLOB_HIDDEN</code></td><td style="text-align:left;"><code>false</code>로 설정하면 Claude가 <a href="/claude-code-docs-ko/tools-reference.html">Glob 도구</a>를 호출할 때 숨김 파일을 결과에서 제외합니다. 기본적으로 포함됩니다. <code>@</code> 파일 자동완성, <code>ls</code>, Grep, Read에는 영향을 주지 않습니다.</td></tr><tr><td style="text-align:left;"><code>CLAUDE_CODE_GLOB_NO_IGNORE</code></td><td style="text-align:left;"><code>false</code>로 설정하면 <a href="/claude-code-docs-ko/tools-reference.html">Glob 도구</a>가 <code>.gitignore</code> 패턴을 준수합니다. 기본적으로 Glob은 gitignore된 파일을 포함하여 모든 일치 파일을 반환합니다.</td></tr><tr><td style="text-align:left;"><code>CLAUDE_CODE_GLOB_TIMEOUT_SECONDS</code></td><td style="text-align:left;">Glob 도구 파일 검색 타임아웃 (초). 기본값: 대부분 플랫폼 20초, WSL 60초</td></tr><tr><td style="text-align:left;"><code>CLAUDE_CODE_IDE_HOST_OVERRIDE</code></td><td style="text-align:left;">IDE 확장 연결에 사용할 호스트 주소를 재정정합니다. Claude Code가 WSL→Windows 라우팅을 포함한 올바른 주소를 자동 감지합니다.</td></tr><tr><td style="text-align:left;"><code>CLAUDE_CODE_IDE_SKIP_AUTO_INSTALL</code></td><td style="text-align:left;">IDE 확장 자동 설치를 건너뜁니다. <a href="/claude-code-docs-ko/settings.html#global-config-settings"><code>autoInstallIdeExtension</code></a>을 <code>false</code>로 설정하는 것과 동일합니다.</td></tr><tr><td style="text-align:left;"><code>CLAUDE_CODE_IDE_SKIP_VALID_CHECK</code></td><td style="text-align:left;"><code>1</code>로 설정하면 연결 시 IDE lockfile 항목의 유효성 검사를 건너뜁니다. IDE가 실행 중인데도 자동 연결이 실패할 때 사용하세요.</td></tr><tr><td style="text-align:left;"><code>CLAUDE_CODE_MAX_OUTPUT_TOKENS</code></td><td style="text-align:left;">대부분 요청의 최대 출력 토큰 수를 설정합니다. 기본값과 상한은 모델에 따라 다릅니다. 이 값을 늘리면 <a href="/claude-code-docs-ko/costs.html#reduce-token-usage">자동 압축</a>이 트리거되기 전의 유효 컨텍스트 윈도우가 줄어듭니다.</td></tr><tr><td style="text-align:left;"><code>CLAUDE_CODE_MAX_RETRIES</code></td><td style="text-align:left;">실패한 API 요청의 재시도 횟수 재정정 (기본값: 10)</td></tr><tr><td style="text-align:left;"><code>CLAUDE_CODE_MAX_TOOL_USE_CONCURRENCY</code></td><td style="text-align:left;">병렬로 실행할 수 있는 읽기 전용 도구 및 서브에이전트의 최대 수 (기본값: 10). 높은 값은 병렬성을 높이지만 더 많은 리소스를 소모합니다.</td></tr><tr><td style="text-align:left;"><code>CLAUDE_CODE_NEW_INIT</code></td><td style="text-align:left;"><code>1</code>로 설정하면 <code>/init</code>가 대화형 설정 흐름을 실행합니다. 코드베이스를 탐색하고 작성하기 전에 CLAUDE.md, 스킬, 훅 중 어떤 것을 생성할지 묻습니다. 미설정 시 <code>/init</code>은 프롬프트 없이 CLAUDE.md를 자동 생성합니다.</td></tr><tr><td style="text-align:left;"><code>CLAUDE_CODE_NO_FLICKER</code></td><td style="text-align:left;"><code>1</code>로 설정하면 <a href="/claude-code-docs-ko/fullscreen.html">전체화면 렌더링</a>을 활성화합니다. 깜빡임을 줄이고 긴 대화에서 메모리 사용량을 안정화하는 리서치 프리뷰입니다.</td></tr><tr><td style="text-align:left;"><code>CLAUDE_CODE_OAUTH_REFRESH_TOKEN</code></td><td style="text-align:left;">Claude.ai 인증용 OAuth 리프레시 토큰. 설정 시 <code>claude auth login</code>이 브라우저 대신 이 토큰을 직접 교환합니다. <code>CLAUDE_CODE_OAUTH_SCOPES</code>가 필요합니다. 자동화 환경에서 인증을 프로비저닝할 때 유용합니다.</td></tr><tr><td style="text-align:left;"><code>CLAUDE_CODE_OAUTH_SCOPES</code></td><td style="text-align:left;">리프레시 토큰이 발급된 OAuth 스코프 (공백으로 구분). <code>&quot;user:profile user:inference user:sessions:claude_code&quot;</code> 등. <code>CLAUDE_CODE_OAUTH_REFRESH_TOKEN</code>이 설정된 경우 필수입니다.</td></tr><tr><td style="text-align:left;"><code>CLAUDE_CODE_OAUTH_TOKEN</code></td><td style="text-align:left;">Claude.ai 인증용 OAuth 액세스 토큰. SDK 및 자동화 환경에서 <code>/login</code>의 대안입니다. 키체인에 저장된 자격 증명보다 우선합니다. <a href="/claude-code-docs-ko/authentication.html#generate-a-long-lived-token"><code>claude setup-token</code></a>으로 생성하세요.</td></tr><tr><td style="text-align:left;"><code>CLAUDE_CODE_OTEL_FLUSH_TIMEOUT_MS</code></td><td style="text-align:left;">보류 중인 OpenTelemetry 스팬 플러시 타임아웃 (밀리초, 기본값: 5000). <a href="/claude-code-docs-ko/monitoring-usage.html">Monitoring</a> 참조.</td></tr><tr><td style="text-align:left;"><code>CLAUDE_CODE_OTEL_HEADERS_HELPER_DEBOUNCE_MS</code></td><td style="text-align:left;">동적 OpenTelemetry 헤더 새로 고침 간격 (밀리초, 기본값: 1740000/29분). <a href="/claude-code-docs-ko/monitoring-usage.html#dynamic-headers">Dynamic headers</a> 참조.</td></tr><tr><td style="text-align:left;"><code>CLAUDE_CODE_OTEL_SHUTDOWN_TIMEOUT_MS</code></td><td style="text-align:left;">종료 시 OpenTelemetry 익스포터 완료 타임아웃 (밀리초, 기본값: 2000). 종료 시 메트릭 손실이 있으면 늘리세요. <a href="/claude-code-docs-ko/monitoring-usage.html">Monitoring</a> 참조.</td></tr><tr><td style="text-align:left;"><code>CLAUDE_CODE_PERFORCE_MODE</code></td><td style="text-align:left;"><code>1</code>로 설정하면 Perforce 인식 쓰기 보호를 활성화합니다. 설정 시 대상 파일에 소유자 쓰기 비트가 없으면 Edit, Write, NotebookEdit이 <code>p4 edit &lt;file&gt;</code> 힌트와 함께 실패합니다. Claude Code가 Perforce 변경 추적을 우회하는 것을 방지합니다.</td></tr><tr><td style="text-align:left;"><code>CLAUDE_CODE_PLUGIN_CACHE_DIR</code></td><td style="text-align:left;">플러그인 루트 디렉토리를 재정정합니다. 이름과 달리 캐시 자체가 아닌 상위 디렉토리를 설정합니다. 기본값: <code>~/.claude/plugins</code></td></tr><tr><td style="text-align:left;"><code>CLAUDE_CODE_PLUGIN_GIT_TIMEOUT_MS</code></td><td style="text-align:left;">플러그인 설치/업데이트 시 git 작업 타임아웃 (밀리초, 기본값: 120000). 대형 리포지토리나 느린 네트워크에서 늘리세요. <a href="/claude-code-docs-ko/plugin-marketplaces.html#git-operations-time-out">Git operations time out</a> 참조.</td></tr><tr><td style="text-align:left;"><code>CLAUDE_CODE_PLUGIN_KEEP_MARKETPLACE_ON_FAILURE</code></td><td style="text-align:left;"><code>1</code>로 설정하면 <code>git pull</code> 실패 시 기존 마켓플레이스 캐시를 유지합니다. 오프라인이나 에어갭 환경에서 재클론이 같은 방식으로 실패할 때 유용합니다.</td></tr><tr><td style="text-align:left;"><code>CLAUDE_CODE_PLUGIN_SEED_DIR</code></td><td style="text-align:left;">읽기 전용 플러그인 시드 디렉토리 경로 (Unix에서 <code>:</code>, Windows에서 <code>;</code>로 구분). 컨테이너 이미지에 미리 채워진 플러그인 디렉토리를 번들할 때 사용합니다. <a href="/claude-code-docs-ko/plugin-marketplaces.html#pre-populate-plugins-for-containers">Pre-populate plugins for containers</a> 참조.</td></tr><tr><td style="text-align:left;"><code>CLAUDE_CODE_PROXY_RESOLVES_HOSTS</code></td><td style="text-align:left;"><code>1</code>로 설정하면 프록시가 DNS 확인을 수행하도록 허용합니다. 프록시가 호스트네임 확인을 처리해야 하는 환경에서 옵트인하세요.</td></tr><tr><td style="text-align:left;"><code>CLAUDE_CODE_RESUME_INTERRUPTED_TURN</code></td><td style="text-align:left;"><code>1</code>로 설정하면 이전 세션이 턴 중간에 종료된 경우 자동으로 재개합니다. SDK 모드에서 모델이 SDK가 프롬프트를 재전송할 필요 없이 계속 진행하도록 사용합니다.</td></tr><tr><td style="text-align:left;"><code>CLAUDE_CODE_SCRIPT_CAPS</code></td><td style="text-align:left;"><code>CLAUDE_CODE_SUBPROCESS_ENV_SCRUB</code>이 설정된 경우 세션당 특정 스크립트 호출 횟수를 제한하는 JSON 객체. 키는 명령 텍스트에 대해 부분 문자열 일치, 값은 정수 호출 제한. 예: <code>{&quot;deploy.sh&quot;: 2}</code>는 <code>deploy.sh</code>를 최대 2번 호출하도록 허용합니다.</td></tr><tr><td style="text-align:left;"><code>CLAUDE_CODE_SCROLL_SPEED</code></td><td style="text-align:left;"><a href="/claude-code-docs-ko/fullscreen.html#adjust-wheel-scroll-speed">전체화면 렌더링</a>에서 마우스 휠 스크롤 배율을 설정합니다. 1~20의 값을 허용합니다. <code>3</code>으로 설정하면 터미널이 증폭 없이 한 노치당 하나의 휠 이벤트를 보낼 때 <code>vim</code>과 일치합니다.</td></tr><tr><td style="text-align:left;"><code>CLAUDE_CODE_SESSIONEND_HOOKS_TIMEOUT_MS</code></td><td style="text-align:left;"><a href="/claude-code-docs-ko/hooks.html#sessionend">SessionEnd</a> 훅의 시간 예산 재정정 (밀리초). 세션 종료, <code>/clear</code>, 대화형 <code>/resume</code>으로 세션 전환에 적용됩니다. 기본 예산은 1.5초이며, 설정 파일에 구성된 훅별 <code>timeout</code> 중 가장 높은 값까지 자동 상향, 최대 60초입니다.</td></tr><tr><td style="text-align:left;"><code>CLAUDE_CODE_SHELL</code></td><td style="text-align:left;">자동 셸 감지를 재정정합니다. 로그인 셸과 선호하는 작업 셸이 다를 때 유용합니다 (예: <code>bash</code> vs <code>zsh</code>)</td></tr><tr><td style="text-align:left;"><code>CLAUDE_CODE_SHELL_PREFIX</code></td><td style="text-align:left;">모든 bash 명령을 감싸는 명령 접두사 (예: 로깅이나 감사용). 예: <code>/path/to/logger.sh</code>는 <code>/path/to/logger.sh &lt;command&gt;</code>를 실행합니다.</td></tr><tr><td style="text-align:left;"><code>CLAUDE_CODE_SIMPLE</code></td><td style="text-align:left;"><code>1</code>로 설정하면 최소 시스템 프롬프트와 Bash, 파일 읽기, 파일 편집 도구만으로 실행합니다. <code>--mcp-config</code>의 MCP 도구는 계속 사용 가능합니다. 훅, 스킬, 플러그인, MCP 서버, 자동 메모리, CLAUDE.md의 자동 발견을 비활성화합니다. <a href="/claude-code-docs-ko/headless.html#start-faster-with-bare-mode"><code>--bare</code></a> CLI 플래그가 이 값을 설정합니다.</td></tr><tr><td style="text-align:left;"><code>CLAUDE_CODE_SKIP_BEDROCK_AUTH</code></td><td style="text-align:left;">Bedrock용 AWS 인증을 건너뜁니다 (예: LLM 게이트웨이 사용 시)</td></tr><tr><td style="text-align:left;"><code>CLAUDE_CODE_SKIP_FOUNDRY_AUTH</code></td><td style="text-align:left;">Microsoft Foundry용 Azure 인증을 건너뜁니다 (예: LLM 게이트웨이 사용 시)</td></tr><tr><td style="text-align:left;"><code>CLAUDE_CODE_SKIP_MANTLE_AUTH</code></td><td style="text-align:left;">Bedrock Mantle용 AWS 인증을 건너뜁니다 (예: LLM 게이트웨이 사용 시)</td></tr><tr><td style="text-align:left;"><code>CLAUDE_CODE_SKIP_VERTEX_AUTH</code></td><td style="text-align:left;">Vertex용 Google 인증을 건너뜁니다 (예: LLM 게이트웨이 사용 시)</td></tr><tr><td style="text-align:left;"><code>CLAUDE_CODE_SUBAGENT_MODEL</code></td><td style="text-align:left;"><a href="/claude-code-docs-ko/model-config.html">Model configuration</a> 참조</td></tr><tr><td style="text-align:left;"><code>CLAUDE_CODE_SUBPROCESS_ENV_SCRUB</code></td><td style="text-align:left;"><code>1</code>로 설정하면 서브프로세스 환경(Bash 도구, 훅, MCP stdio 서버)에서 Anthropic 및 클라우드 프로바이더 자격 증명을 제거합니다. 부모 Claude 프로세스는 API 호출용 자격 증명을 유지하지만, 자식 프로세스는 셸 확장을 통한 시크릿 유출 프롬프트 인젝션 공격에 노출을 줄입니다. Linux에서는 Bash 서브프로세스를 분리된 PID 네임스페이스에서 실행하여 호스트 프로세스 환경을 읽지 못하게 합니다.</td></tr><tr><td style="text-align:left;"><code>CLAUDE_CODE_SYNC_PLUGIN_INSTALL</code></td><td style="text-align:left;">비대화형 모드(<code>-p</code> 플래그)에서 <code>1</code>로 설정하면 첫 번째 쿼리 전 플러그인 설치 완료를 대기합니다. 미설정 시 플러그인이 백그라운드에서 설치되어 첫 번째 턴에 사용할 수 없을 수 있습니다.</td></tr><tr><td style="text-align:left;"><code>CLAUDE_CODE_SYNC_PLUGIN_INSTALL_TIMEOUT_MS</code></td><td style="text-align:left;">동기 플러그인 설치 타임아웃 (밀리초). 초과 시 Claude Code는 플러그인 없이 진행하고 에러를 로깅합니다. 미설정 시 동기 설치는 완료까지 대기합니다.</td></tr><tr><td style="text-align:left;"><code>CLAUDE_CODE_SYNTAX_HIGHLIGHT</code></td><td style="text-align:left;"><code>false</code>로 설정하면 diff 출력에서 구문 강조를 비활성화합니다. 색상이 터미널 설정과 충돌할 때 유용합니다.</td></tr><tr><td style="text-align:left;"><code>CLAUDE_CODE_TASK_LIST_ID</code></td><td style="text-align:left;">세션 간 작업 목록을 공유합니다. 여러 Claude Code 인스턴스에 동일한 ID를 설정하여 공유 작업 목록을 조율합니다. <a href="/claude-code-docs-ko/interactive-mode.html#task-list">작업 목록</a> 참조.</td></tr><tr><td style="text-align:left;"><code>CLAUDE_CODE_TEAM_NAME</code></td><td style="text-align:left;">이 팀원이 속한 에이전트 팀 이름. <a href="/claude-code-docs-ko/agent-teams.html">agent team</a> 멤버에 자동 설정됩니다.</td></tr><tr><td style="text-align:left;"><code>CLAUDE_CODE_TMPDIR</code></td><td style="text-align:left;">내부 임시 파일에 사용할 임시 디렉토리를 재정정합니다. Claude Code는 이 경로에 <code>/claude-{uid}/</code>(Unix) 또는 <code>/claude/</code>(Windows)를 추가합니다.</td></tr><tr><td style="text-align:left;"><code>CLAUDE_CODE_USE_BEDROCK</code></td><td style="text-align:left;"><a href="/claude-code-docs-ko/amazon-bedrock.html">Bedrock</a> 사용</td></tr><tr><td style="text-align:left;"><code>CLAUDE_CODE_USE_FOUNDRY</code></td><td style="text-align:left;"><a href="/claude-code-docs-ko/microsoft-foundry.html">Microsoft Foundry</a> 사용</td></tr><tr><td style="text-align:left;"><code>CLAUDE_CODE_USE_MANTLE</code></td><td style="text-align:left;">Bedrock <a href="/claude-code-docs-ko/amazon-bedrock.html#use-the-mantle-endpoint">Mantle endpoint</a> 사용</td></tr><tr><td style="text-align:left;"><code>CLAUDE_CODE_USE_POWERSHELL_TOOL</code></td><td style="text-align:left;"><code>1</code>로 설정하면 Windows에서 PowerShell 도구를 활성화합니다 (옵트인 프리뷰). Claude가 Git Bash를 통하지 않고 PowerShell 명령을 네이티브로 실행할 수 있습니다. WSL이 아닌 네이티브 Windows만 지원합니다.</td></tr><tr><td style="text-align:left;"><code>CLAUDE_CODE_USE_VERTEX</code></td><td style="text-align:left;"><a href="/claude-code-docs-ko/google-vertex-ai.html">Vertex</a> 사용</td></tr><tr><td style="text-align:left;"><code>CLAUDE_CONFIG_DIR</code></td><td style="text-align:left;">설정 디렉토리를 재정정합니다 (기본값: <code>~/.claude</code>). 모든 설정, 자격 증명, 세션 기록, 플러그인이 이 경로 아래에 저장됩니다. 여러 계정을 나란히 실행할 때 유용합니다.</td></tr><tr><td style="text-align:left;"><code>CLAUDE_ENABLE_BYTE_WATCHDOG</code></td><td style="text-align:left;"><code>1</code>로 설정하면 바이트 수준 스트리밍 유휴 워치독을 강제 활성화하고, <code>0</code>으로 설정하면 강제 비활성화합니다. 미설정 시 Anthropic API 연결에 기본적으로 활성화됩니다.</td></tr><tr><td style="text-align:left;"><code>CLAUDE_ENABLE_STREAM_WATCHDOG</code></td><td style="text-align:left;"><code>1</code>로 설정하면 이벤트 수준 스트리밍 유휴 워치독을 활성화합니다. 기본적으로 비활성화됩니다. Bedrock, Vertex, Foundry에서는 사용 가능한 유일한 유휴 워치독입니다.</td></tr><tr><td style="text-align:left;"><code>CLAUDE_ENV_FILE</code></td><td style="text-align:left;">Claude Code가 각 Bash 명령 전에 소싱하는 셸 스크립트 경로. virtualenv나 conda 활성화를 명령 간에 유지하는 데 사용합니다.</td></tr><tr><td style="text-align:left;"><code>CLAUDE_REMOTE_CONTROL_SESSION_NAME_PREFIX</code></td><td style="text-align:left;">명시적 이름이 제공되지 않을 때 자동 생성되는 <a href="/claude-code-docs-ko/remote-control.html">Remote Control</a> 세션 이름의 접두사. 기본값은 호스트네임입니다.</td></tr><tr><td style="text-align:left;"><code>CLAUDE_STREAM_IDLE_TIMEOUT_MS</code></td><td style="text-align:left;">스트리밍 유휴 워치독이 정체된 연결을 닫기 전의 타임아웃 (밀리초). 바이트 수준 워치독(Anthropic API): 기본 및 최소 <code>300000</code>(5분). 이벤트 수준 워치독: 기본 <code>90000</code>(90초), 최소 없음.</td></tr><tr><td style="text-align:left;"><code>DISABLE_AUTOUPDATER</code></td><td style="text-align:left;"><code>1</code>로 설정하면 자동 업데이트를 비활성화합니다.</td></tr><tr><td style="text-align:left;"><code>DISABLE_AUTO_COMPACT</code></td><td style="text-align:left;"><code>1</code>로 설정하면 컨텍스트 한도에 가까워질 때 자동 압축을 비활성화합니다. 수동 <code>/compact</code> 명령은 계속 사용 가능합니다.</td></tr><tr><td style="text-align:left;"><code>DISABLE_COMPACT</code></td><td style="text-align:left;"><code>1</code>로 설정하면 모든 압축을 비활성화합니다: 자동 압축과 수동 <code>/compact</code> 명령 모두.</td></tr><tr><td style="text-align:left;"><code>DISABLE_COST_WARNINGS</code></td><td style="text-align:left;"><code>1</code>로 설정하면 비용 경고 메시지를 비활성화합니다.</td></tr><tr><td style="text-align:left;"><code>DISABLE_DOCTOR_COMMAND</code></td><td style="text-align:left;"><code>1</code>로 설정하면 <code>/doctor</code> 명령을 숨깁니다. 관리형 배포에서 유용합니다.</td></tr><tr><td style="text-align:left;"><code>DISABLE_ERROR_REPORTING</code></td><td style="text-align:left;"><code>1</code>로 설정하면 Sentry 에러 보고를 옵트아웃합니다.</td></tr><tr><td style="text-align:left;"><code>DISABLE_EXTRA_USAGE_COMMAND</code></td><td style="text-align:left;"><code>1</code>로 설정하면 사용자가 추가 사용량을 구매할 수 있는 <code>/extra-usage</code> 명령을 숨깁니다.</td></tr></tbody></table>',4)])])}const g=e(c,[["render",a]]);export{f as __pageData,g as default};
